# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

func handleUniversalLink(url: URL) {
    guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
          let token = components.queryItems?.first(where: { $0.name == "token" })?.value else {
        return
    }

    // Navigate to the password reset screen with the token
    let storyboard = UIStoryboard(name: "Main", bundle: nil)
    let viewController = storyboard.instantiateViewController(withIdentifier: "PasswordResetViewController") as! PasswordResetViewController
    viewController.token = token
    
    UIApplication.shared.keyWindow?.rootViewController?.present(viewController, animated: true, completion: nil)
}

func application(_ application: UIApplication, continue userActivity: NSUserActivity) {
    if userActivity.webpageURL != nil {
        handleUniversalLink(url: userActivity.webpageURL!)
    }
}